ee:message.ee:set-payload:
%dw 2.0
output application/java
---
{
    parts: {
        file: {
            headers: {
                "Content-Disposition": {
                    "name": "file",
                    "filename": if (vars.originalFileName contains ".") vars.originalFileName else (vars.originalFileName ++ ".pdf")
                },
                "Content-Type": "application/pdf"
            },
            content: payload
        }
    }
}

%dw 2.0
output application/json
var sfdc = vars.purchaseOrderData[0] default {}
var idpPayload = payload default {}

var cleanIdpAmount = (idpPayload.totalAmount replace /[^\d.]/ with "") as Number default 0
var cleanSfdcAmount = (sfdc.Starting_PO_Balance__c default "0") as Number

// Normalization: removing line breaks, HTML tags, and converting to lowercase
var cleanIdpBilling = lower(idpPayload.billingAddress default "" replace /\n/ with " " replace /[^\w\s]/ with "")
var cleanSfdcBilling = lower(sfdc.Payment_Billing_Address__c default "" replace /<[^>]+>/ with " " replace /[^\w\s]/ with "")

var poNumberStatus = if(sfdc.Purchase_Order_Reference__c == idpPayload.poNumber) "ok" else "fail"
var amountStatus = if(cleanSfdcAmount == cleanIdpAmount) "ok" else "fail"

// Basic fuzzy match: If at least 50% of the words from the IDP address are present in the Salesforce address
var idpWords = cleanIdpBilling splitBy " " filter ((item) -> not isEmpty(item))
var matchCount = sizeOf(idpWords filter ((word) -> cleanSfdcBilling contains word))
var billingStatus = if(sizeOf(idpWords) > 0 and (matchCount / sizeOf(idpWords)) >= 0.5) "ok" else "fail"

var order = vars.orderData[0] default {}
var sfdcShippingConcat = (order.Selected_Shipping_Address__r.Street_1__c default "") ++ " " ++ 
                         (order.Selected_Shipping_Address__r.Street_2__c default "") ++ " " ++ 
                         (order.Selected_Shipping_Address__r.City__c default "") ++ " " ++ 
                         (order.Selected_Shipping_Address__r.State__c default "") ++ " " ++ 
                         (order.Selected_Shipping_Address__r.Zip_Code__c default "")

var cleanIdpShipping = lower(idpPayload.shippingAddress default "" replace /\n/ with " " replace /[^\w\s]/ with "")
var cleanSfdcShipping = lower(sfdcShippingConcat replace /<[^>]+>/ with " " replace /[^\w\s]/ with "")

var idpShipWords = cleanIdpShipping splitBy " " filter ((item) -> not isEmpty(item))
var matchCountShip = sizeOf(idpShipWords filter ((word) -> cleanSfdcShipping contains word))
var shippingStatus = if(sizeOf(idpShipWords) > 0 and (matchCountShip / sizeOf(idpShipWords)) >= 0.5) "ok" else "fail"

var isSuccess = (poNumberStatus == "ok") and (amountStatus == "ok") and (billingStatus == "ok") and (shippingStatus == "ok")
---
{
    zip: vars.s3FileName default vars.archiveFileName default vars.originalFileName default "",
    pdf: vars.pdfFileName default "",
    status: if(sizeOf(vars.purchaseOrderData default []) == 0) "fail" else if(isSuccess) "ok" else "fail",
    details: {
        poNumber: { status: poNumberStatus, idp: idpPayload.poNumber, sfdc: sfdc.Purchase_Order_Reference__c },
        totalAmount: { status: amountStatus, idp: cleanIdpAmount, sfdc: cleanSfdcAmount },
        billingAddress: { status: billingStatus, idp: cleanIdpBilling, sfdc: cleanSfdcBilling },
        shippingAddress: { status: shippingStatus, idp: cleanIdpShipping, sfdc: cleanSfdcShipping }
    }
}
